"""BypassRunner — 통과 노드."""

from __future__ import annotations

from typing import Any


class BypassRunner:
    async def run(self, node: Any, inputs: dict[str, Any], ctx: Any) -> dict[str, Any]:
        # 우선순위: text > input > 첫 STR/Generator > 첫 값
        for key in ("text", "input"):
            if key in inputs:
                return {"result": inputs[key]}

        for value in inputs.values():
            if isinstance(value, str) or hasattr(value, "__next__"):
                return {"result": value}

        if inputs:
            first_value = next(iter(inputs.values()))
            return {"result": first_value}

        # 입력 없으면 output 타입에 맞는 기본값
        if node.outputs:
            out_type = node.outputs[0].type.upper()
            defaults = {"STR": "", "INT": 0, "FLOAT": 0.0, "BOOL": False, "LIST": [], "DICT": {}}
            return {"result": defaults.get(out_type, "")}

        return {"result": ""}
